import requests
from enum import Enum

class ApiVersioningStrategy(Enum):
    PATH = "path"
    QUERY_PARAM = "query_param"
    CUSTOM_HEADER = "custom_header"
    ACCEPT_HEADER = "accept_header"

class EdenApiClient:
    def __init__(self, base_url: str, api_version: int, strategy: ApiVersioningStrategy = ApiVersioningStrategy.PATH):
        self.base_url = base_url.rstrip('/')
        self.api_version = api_version
        self.strategy = strategy
        self.session = requests.Session()

    def _prepare_request(self, endpoint: str, params: dict = None, headers: dict = None):
        params = params or {}
        headers = headers or {}
        url = f"{self.base_url}"

        if self.strategy == ApiVersioningStrategy.PATH:
            url += f"/v{self.api_version}/{endpoint.lstrip('/')}"
        else:
            url += f"/{endpoint.lstrip('/')}"

        if self.strategy == ApiVersioningStrategy.QUERY_PARAM:
            params["api-version"] = str(self.api_version)
        elif self.strategy == ApiVersioningStrategy.CUSTOM_HEADER:
            headers["X-API-Version"] = str(self.api_version)
        elif self.strategy == ApiVersioningStrategy.ACCEPT_HEADER:
            # Example: application/vnd.myapi.v1+json
            headers["Accept"] = f"application/vnd.myapi.v{self.api_version}+json"

        return url, params, headers

    def get(self, endpoint: str, params: dict = None, headers: dict = None):
        url, prepared_params, prepared_headers = self._prepare_request(endpoint, params, headers)
        return self.session.get(url, params=prepared_params, headers=prepared_headers)

    def post(self, endpoint: str, json: dict = None, data: dict = None, params: dict = None, headers: dict = None):
        url, prepared_params, prepared_headers = self._prepare_request(endpoint, params, headers)
        return self.session.post(url, json=json, data=data, params=prepared_params, headers=prepared_headers)

    def put(self, endpoint: str, json: dict = None, data: dict = None, params: dict = None, headers: dict = None):
        url, prepared_params, prepared_headers = self._prepare_request(endpoint, params, headers)
        return self.session.put(url, json=json, data=data, params=prepared_params, headers=prepared_headers)

    def delete(self, endpoint: str, params: dict = None, headers: dict = None):
        url, prepared_params, prepared_headers = self._prepare_request(endpoint, params, headers)
        return self.session.delete(url, params=prepared_params, headers=prepared_headers)

    def get_users(self, user_id: str = None, query_params: dict = None):
        endpoint = "users"
        if user_id:
            endpoint += f"/{user_id}"
        return self.get(endpoint, params=query_params)

    def create_user(self, user_data: dict):
        return self.post("users", json=user_data)

    def update_user(self, user_id: str, user_data: dict):
        return self.put(f"users/{user_id}", json=user_data)

    def delete_user(self, user_id: str):
        return self.delete(f"users/{user_id}")
